#include <chrono>
#include <cmath>
#include <cstdio>
#include <iostream>
#include <iomanip>
#include <limits>
#include <utility>
#include <cstdlib>
#include <omp.h>

#define N 2048
#define IDX(i, j) ((i) + (j) * N)

void initialize_data(float* f) {
  for (int j = 0; N > j; ++j) {
    for (int i = 0; N > i; ++i) {
      if (0 == i || N - 1 == i) {
        f[IDX(i, j)] = sinf(j * 2 * M_PI / (N - 1));
      } else if (0 == j || N - 1 == j) {
        f[IDX(i, j)] = sinf(i * 2 * M_PI / (N - 1));
      } else {
        f[IDX(i, j)] = 0.0f;
      }
    }
  }
}

int main() {
  auto start_time = std::chrono::steady_clock::now();

  float* f = (float*)aligned_alloc(64, N * N * sizeof(float));
  float* f_old = (float*)aligned_alloc(64, N * N * sizeof(float));

  initialize_data(f);
  initialize_data(f_old);

  float error = std::numeric_limits<float>::max();
  const float tolerance = 1.e-5f;

  const int max_iters = 10000;
  int num_iters = 0;

  auto start = std::chrono::steady_clock::now();

#pragma omp target data map(tofrom : f[0:N * N], f_old[0:N * N])
  {
    while (tolerance < error && max_iters > num_iters) {
      float errsum = 0.0f;

      if ((num_iters & 1) == 0) {
#pragma omp target teams distribute parallel for collapse(2) reduction(+ : errsum)
        for (int j = 1; j <= N - 2; ++j) {
          for (int i = 1; i <= N - 2; ++i) {
            float newv = 0.25f * (f_old[IDX(i + 1, j)] +
                                  f_old[IDX(i - 1, j)] +
                                  f_old[IDX(i, j + 1)] +
                                  f_old[IDX(i, j - 1)]);
            float df = newv - f_old[IDX(i, j)];
            f[IDX(i, j)] = newv;
            errsum += df * df;
          }
        }
      } else {
#pragma omp target teams distribute parallel for collapse(2) reduction(+ : errsum)
        for (int j = 1; j <= N - 2; ++j) {
          for (int i = 1; i <= N - 2; ++i) {
            float newv = 0.25f * (f[IDX(i + 1, j)] +
                                  f[IDX(i - 1, j)] +
                                  f[IDX(i, j + 1)] +
                                  f[IDX(i, j - 1)]);
            float df = newv - f[IDX(i, j)];
            f_old[IDX(i, j)] = newv;
            errsum += df * df;
          }
        }
      }

      error = sqrtf(errsum / (N * N));

      if (0 == num_iters % 1000) {
        std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
      }

      ++num_iters;
    }
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

  if (tolerance >= error && max_iters > num_iters) {
    std::cout << "PASS" << std::endl;
  } else {
    std::cout << "FAIL" << std::endl;
    free(f);
    free(f_old);
    return -1;
  }

  free(f);
  free(f_old);

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}
